                })
        u = data.get("usage", {}) or {}
        usage = {
            "input": u.get("input_tokens", 0),
            "output": u.get("output_tokens", 0),
            "total": u.get("input_tokens", 0) + u.get("output_tokens", 0),
        }
        return {
            "content": content_text,
            "tool_calls": tool_calls,
            "usage": usage,
        }


